async function clearFormFields(){const e=document.getElementById("apasxolhseisForm");e?e.querySelectorAll("input, select, textarea").forEach(e=>{e.classList.contains("notCleared")||e.closest&&e.closest(".ts-wrapper, .ts-control, .ts-dropdown")||("INPUT"===e.tagName?"checkbox"===e.type||"radio"===e.type?e.checked=!1:"number"===e.type?e.value="0":"text"===e.type&&(e.value=""):"SELECT"===e.tagName?e.selectedIndex=0:"TEXTAREA"===e.tagName&&(e.value=""))}):console.warn("Το στοιχείο 'apasxolhseisForm' δεν βρέθηκε.")}